feed:
  {{ group_name | replace: "&", "&" }} - Toulouse Tech Hub
  Prochains évènements de {{ group_name | replace: "&", "&" }} à Toulouse
  Toulouse Tech Hub


  urn:toulouse-tech-hub:group:{{ include.group_slug }}
  {{ site.time | date: "%Y-%m-%dT%T" }}+01:00
{%- for event in site.events reversed -%}
{%- if event.groupId != include.group_slug -%}{%- continue -%}{%- endif -%}
{%- assign event_time = event.datePublished | date: "%s" | plus: 0 -%}
{%- if event_time > now_time -%}{%- continue -%}{%- endif -%}
{%- assign tz = event.dateIso | date: "%z" -%}
{%- assign date_part = event.dateIso | date: "%Y-%m-%d" -%}
{%- capture image_path %}event-imgs/{{ date_part }}-{{ event.groupId }}-{{ event.eventId }}.webp{% endcapture -%}

    urn:{{ event.eventId }}
    {{ event.datePublished | date: "%Y-%m-%dT%T" }}{{ tz | slice: 0, 3 }}:00
    {{ event.dateFr }} à {{ event.timeFr }} : {{ event.title | replace: "&", "&" | replace: "<", "<" }}

    {{ event.community | replace: "&", "&" | replace: "<", "<" }}


    {{ event.content | replace: "&", "&" | replace: "<", "<" | replace: ">", ">" }}

{%- endfor %}
